import { d3_map } from '../../../core/d3-constants';
import { getPattern } from './pattern';
import { getByEncode } from './encode';
import { getByGradient } from './gradient';
import { getImage } from './imagePattern';
import { exportAs } from './export-as';
import { getExpressionValue } from '../../parser/parser-helpers';

let ALLOWED_CONFIG_OPERATORS = d3_map();
ALLOWED_CONFIG_OPERATORS.set('pattern', getPattern);
ALLOWED_CONFIG_OPERATORS.set('encode', getByEncode);
ALLOWED_CONFIG_OPERATORS.set('gradient', getByGradient);
ALLOWED_CONFIG_OPERATORS.set('image', getImage);
ALLOWED_CONFIG_OPERATORS.set('as', exportAs);
ALLOWED_CONFIG_OPERATORS.set('expression', getExpressionValue);


let ALLOWED_REPARSE_MARKS_CONFIG = d3_map();
ALLOWED_REPARSE_MARKS_CONFIG.set('text', ["textOverflow"]);

let ALLOWED_REPARSE_OPERATORS = d3_map();
//map by component name - while fetching this component Registry.get('textMarkOverflow') should be used. Registry is used to avoid default zc.js size
ALLOWED_REPARSE_OPERATORS.set('textOverflow', 'textMarkOverflow');
export { ALLOWED_CONFIG_OPERATORS, ALLOWED_REPARSE_OPERATORS, ALLOWED_REPARSE_MARKS_CONFIG };
